updateFields.description:
={{ (() => {
  const raw = $fromAI('description', 'Descricao padronizada e visivel ao cliente. Inclua obrigatoriamente as linhas E-mail e URL do imovel com o link publico exato do imovel. Use apenas: Visita Novian, nome, telefone, e-mail, imovel, endereco, URL do imovel, data/horario, corretora responsavel e origem. Escreva em ASCII simples, sem acentos ou cedilha, e nao inclua comentarios ou observacoes sobre o lead', 'string') || '';
  const sanitized = String(raw)
    .replace(/\u00A0/g, ' ')
    .replace(/\r\n/g, '\n')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\uFFFD/g, '')
    .replace(/[^\x20-\x7E\n]/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  const requiredLabels = [
    'Visita Novian',
    'Nome:',
    'Telefone:',
    'E-mail:',
    'Imovel:',
    'Endereco:',
    'URL do imovel:',
    'Data e horario:',
    'Corretora responsavel:',
    'Origem:',
  ];
  const missingLabels = requiredLabels.filter((label) => !sanitized.includes(label));
  if (missingLabels.length) {
    throw new Error('Description da visita precisa incluir: ' + missingLabels.join(', '));
  }
  if (!/E-mail:\s*[^\s@]+@[^\s@]+\.[^\s@]+/i.test(sanitized)) {
    throw new Error('Description da visita precisa incluir o e-mail informado pelo lead');
  }
  if (!/URL do imovel:\s*https?:\/\/\S+/i.test(sanitized)) {
    throw new Error('Description da visita precisa incluir a URL publica do imovel');
  }
  return sanitized;
})() }}

